const payload = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const filepath = typeof payload.filepath === 'string' ? payload.filepath.trim() : '';
const filename = typeof payload.filename === 'string' && payload.filename.trim() ? payload.filename.trim() : (filepath ? filepath.split('/').pop() : 'inline-memory.txt');
const content = typeof payload.content === 'string' ? payload.content : '';
const modifiedEpoch = payload.modifiedEpoch !== undefined && payload.modifiedEpoch !== null ? Number(payload.modifiedEpoch) : null;
const projectSlug = typeof payload.project_slug === 'string' && payload.project_slug.trim() ? payload.project_slug.trim() : null;
const rawSource = payload.source;
const sourceInfo = typeof rawSource === 'string' ? { kind: rawSource.trim() || 'manual_ingest', label: rawSource.trim() || 'manual_ingest', path: filepath || null, note: null } : (rawSource && typeof rawSource === 'object' ? (() => { const kind = typeof rawSource.kind === 'string' && rawSource.kind.trim() ? rawSource.kind.trim() : 'manual_ingest'; const label = typeof rawSource.label === 'string' && rawSource.label.trim() ? rawSource.label.trim() : kind; return { kind, label, path: typeof rawSource.path === 'string' && rawSource.path.trim() ? rawSource.path.trim() : (filepath || null), note: typeof rawSource.note === 'string' && rawSource.note.trim() ? rawSource.note.trim() : null }; })() : { kind: 'manual_ingest', label: 'manual_ingest', path: filepath || null, note: null });
const requestedCategory = typeof payload.category === 'string' && payload.category.trim() ? payload.category.trim() : 'project_note';
const errors = [];
if (!filepath && !content.trim()) errors.push('Provide filepath and/or content');
if (payload.filepath !== undefined && typeof payload.filepath !== 'string') errors.push('filepath must be a string when provided');
if (payload.content !== undefined && typeof payload.content !== 'string') errors.push('content must be a string when provided');
if (payload.project_slug !== undefined && payload.project_slug !== null && typeof payload.project_slug !== 'string') errors.push('project_slug must be a string when provided');
if (!content.trim()) errors.push('content is required for crispybrain-ingest');
if (errors.length > 0) return [{ json: { request_ok: false, ok: false, error: { code: 'INVALID_INGEST_INPUT', message: errors.join('; ') }, filepath: filepath || null, filename, project_slug: projectSlug, inserted_count: 0, total_chunks: 0 } }];
return [{ json: { request_ok: true, filepath: filepath || `inline://${filename}`, filename, content, modifiedEpoch, projectSlug, source: sourceInfo.label, sourceInfo, category: requestedCategory, requestedCategory, ingestedAt: new Date().toISOString() } }];

const data = $input.first().json;
const chunkSize = 1200;
const overlap = 200;
const normalize = (text) => text.replace(/\r\n/g, '\n').replace(/\t/g, '  ').trim();
const text = normalize(data.content || '');
if (!text) throw new Error('Content is empty after normalization');
const chunks = [];
let start = 0;
while (start < text.length) {
  let end = Math.min(start + chunkSize, text.length);
  if (end < text.length) {
    const windowStart = Math.max(start + Math.floor(chunkSize * 0.6), start);
    const boundarySlice = text.slice(windowStart, end);
    const breakCandidates = [boundarySlice.lastIndexOf('\n\n'), boundarySlice.lastIndexOf('\n'), boundarySlice.lastIndexOf('. '), boundarySlice.lastIndexOf(' ')].filter((idx) => idx > 0);
    if (breakCandidates.length > 0) end = windowStart + Math.max(...breakCandidates) + 1;
  }
  const chunkText = text.slice(start, end).trim();
  if (chunkText) chunks.push(chunkText);
  if (end >= text.length) break;
  start = Math.max(end - overlap, start + 1);
}
if (chunks.length === 0) throw new Error('Chunking produced zero chunks');
if (chunks.length > 200) throw new Error(`Refusing to embed ${chunks.length} chunks in one run`);
return [{ json: { ...data, totalChunks: chunks.length, chunks: chunks.map((chunkText, index) => ({ chunkIndex: index + 1, totalChunks: chunks.length, title: `${data.filename} :: chunk ${String(index + 1).padStart(2, '0')}`, content: chunkText })) } }];

const { chunks, filepath, filename, modifiedEpoch, projectSlug, source, sourceInfo, category, requestedCategory, ingestedAt, totalChunks } = $input.first().json;
if (!Array.isArray(chunks) || chunks.length === 0) throw new Error('Missing chunks array');
return [{ json: { filepath, filename, modifiedEpoch, projectSlug, source, sourceInfo, category, requestedCategory, ingestedAt, totalChunks, chunks, inputs: chunks.map((chunk) => chunk.content) } }];

const base = $('Build Embedding Batch Request').first().json;
const response = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const embeddings = Array.isArray(response.embeddings) ? response.embeddings : (Array.isArray(response.embedding) ? [response.embedding] : null);
if (!Array.isArray(embeddings) || embeddings.length === 0) throw new Error('Embedding response missing embeddings[]');
if (embeddings.length !== base.chunks.length) throw new Error(`Embedding count mismatch: got ${embeddings.length}, expected ${base.chunks.length}`);
const escapeSql = (value) => String(value ?? '').replace(/'/g, "''");
const values = base.chunks.map((chunk, index) => {
  const embedding = embeddings[index];
  if (!Array.isArray(embedding) || embedding.length === 0) throw new Error(`Embedding missing or invalid for chunk ${chunk.chunkIndex}`);
  const metadata = { filename: base.filename, filepath: base.filepath, modified_epoch: base.modifiedEpoch, ingested_at: base.ingestedAt, project_slug: base.projectSlug, chunk_index: chunk.chunkIndex, total_chunks: chunk.totalChunks, source_label: base.source, source_info: base.sourceInfo, requested_category: base.requestedCategory ?? base.category };
  const metadataSql = `'${escapeSql(JSON.stringify(metadata))}'::jsonb`;
  const embeddingSql = `'[${embedding.join(',')}]'::vector`;
  const categorySql = `(SELECT COALESCE((SELECT name FROM memory_categories WHERE name = '${escapeSql(base.category)}'), 'project_note'))`;
  return `('${escapeSql(base.source)}',${categorySql},'${escapeSql(chunk.title)}','${escapeSql(chunk.content)}',ARRAY['crispybrain','chunked']::text[],${metadataSql},${embeddingSql})`;
});
const query = `
INSERT INTO memories (source, category, title, content, tags, metadata_json, embedding)
VALUES
${values.join(',\n')}
RETURNING id, title, source, category, created_at;
`;
return [{ json: { filepath: base.filepath, filename: base.filename, projectSlug: base.projectSlug, totalChunks: base.totalChunks, source: base.source, query } }];

const inserted = $input.all();
const base = $('Prepare Insert Query').first().json;
const toIso = (value) => {
  if (value === null || value === undefined || value === '') return null;
  if (typeof value === 'string') return value;
  const safeDate = value instanceof Date ? value : new Date(value);
  return Number.isNaN(safeDate.getTime()) ? null : safeDate.toISOString();
};
return [{ json: { ok: true, filepath: base.filepath, filename: base.filename, project_slug: base.projectSlug, source: base.source, inserted_count: inserted.length, total_chunks: base.totalChunks, inserted_rows: inserted.map((item) => ({ id: item.json.id, title: item.json.title, source: item.json.source, category: item.json.category, created_at: toIso(item.json.created_at) })) } }];
